import React, { useEffect, useState } from "react";
import "../../styles/Todo.css";
import RoutineModal from "./RoutineModal";

const TodoModal = ({
    isOpen,
    onClose,
    onSave,
    onDelete,
    initialTodo,
}) => {
    const isEditMode = Boolean(initialTodo);

    const [category, setCategory] = useState("공부");
    const [text, setText] = useState("");
    const [routine, setRoutine] = useState(null);

    const [isRoutineModalOpen, setIsRoutineModalOpen] = useState(false);

    useEffect(() => {
        if (!isOpen) return;

        setCategory(initialTodo?.category || "공부");
        setText(initialTodo?.text || "");
        setRoutine(initialTodo?.routine || null);
    }, [isOpen, initialTodo]);

    if (!isOpen) return null;

    const handleSave = () => {
        if (!text.trim()) return;

        onSave({
            text: text.trim(),
            category,
            routine,
        });
    };

    return (
        <div className="modal-overlay" onClick={onClose}>
            <div
                className="modal-container"
                onClick={(e) => e.stopPropagation()}
            >
                <div className="modal-title">
                    {isEditMode ? "할 일 수정하기" : "할 일 추가하기"}
                </div>

                <div className="modal-section">
                    <div className="modal-label">카테고리</div>
                    <div className="modal-categories">
                        {["공부", "운동", "동아리"].map((cat) => (
                            <label key={cat}>
                                <input
                                    type="radio"
                                    name="category"
                                    value={cat}
                                    checked={category === cat}
                                    onChange={() => setCategory(cat)}
                                />
                                {cat}
                            </label>
                        ))}
                    </div>
                </div>

                <div className="modal-section">
                    <div className="modal-label">내용</div>
                    <div className="input-wrapper">
                        <input
                            type="text"
                            className="text-input"
                            placeholder="내용을 입력해주세요"
                            value={text}
                            onChange={(e) => setText(e.target.value)}
                        />
                    </div>
                </div>

                <div className="modal-section">
                    <button
                        type="button"
                        className="routine-row"
                        onClick={() => setIsRoutineModalOpen(true)}
                    >
                        <div className="routine-label">루틴 등록하기</div>
                        <div className="routine-button">{"›"}</div>
                    </button>
                </div>

                <div className="modal-actions">
                    <button
                        className={`leftbutton ${isEditMode ? "" : "disabled"}`}
                        onClick={onDelete}
                        disabled={!isEditMode}
                    >
                        삭제
                    </button>
                    <button
                        className={`rightbutton ${text.trim() ? "" : "disabled"}`}
                        onClick={handleSave}
                        disabled={!text.trim()}
                    >
                        저장
                    </button>
                </div>

                <RoutineModal
                    isOpen={isRoutineModalOpen}
                    initialRoutine={routine}
                    onClose={() => setIsRoutineModalOpen(false)}
                    onSave={(newRoutine) => {
                        setRoutine(newRoutine);
                        setIsRoutineModalOpen(false);
                    }}
                />
            </div>
        </div>
    );
};

export default TodoModal;
